// Catégoriser chaque réclamation selon son niveau d'escalade
const items = $input.all();
const maintenant = new Date();

return items.map(item => {
  const c = item.json;
  const minutesRestantes = c.minutesRestantes;
  const heuresDeRetard = c.heuresDeRetard;

  let niveauEscalade = 'Normal';
  let actionRequise = '';
  let destinataireRole = '';
  let couleurAlerte = '#27ae60';

  if (heuresDeRetard > 0) {
    // SLA DÉPASSÉ
    if (heuresDeRetard >= 24) {
      niveauEscalade = 'CRITIQUE';
      actionRequise = 'Escalade Direction Générale';
      destinataireRole = 'Directeur';
      couleurAlerte = '#8e1a1a';
    } else if (heuresDeRetard >= 8) {
      niveauEscalade = 'ROUGE';
      actionRequise = 'Escalade Responsable Département';
      destinataireRole = 'ResponsableDept';
      couleurAlerte = '#c0392b';
    } else {
      niveauEscalade = 'ORANGE';
      actionRequise = 'Escalade Responsable Agence';
      destinataireRole = 'ResponsableAgence';
      couleurAlerte = '#e67e22';
    }
  } else if (minutesRestantes <= 60) {
    // IMMINENCE SLA (moins de 1h restante)
    niveauEscalade = 'AVERTISSEMENT';
    actionRequise = 'Alerte Agent - SLA Imminent';
    destinataireRole = 'Agent';
    couleurAlerte = '#f39c12';
  }

  return {
    json: {
      ...c,
      niveauEscalade,
      actionRequise,
      destinataireRole,
      couleurAlerte,
      timestampVerification: maintenant.toISOString(),
      estEnRetard: heuresDeRetard > 0
    }
  };
}).filter(item => item.json.niveauEscalade !== 'Normal');

// Résumé de la vérification SLA
const items = $input.all();
const maintenant = new Date().toISOString();

const stats = {
  totalEscalades: items.length,
  timestampVerification: maintenant
};

console.log(`[SmartBank SLA] Escalades traitées: ${items.length}`);

return [{ json: stats }];
